 35→function parapetPlacementHint(roofSystem) {
 36→  switch (roofSystem?.roofType || 'flat') {
 37→    case 'shed':
 38→      return 'Attached parapets on shed roofs snap only to the high edge and rake edges. The low eave edge is excluded.';
 39→    case 'gable':
 40→    case 'box_gable':
 41→    case 'pyramid_hipped':
 42→    case 'domed':
 43→    case 'dropped_eaves':
 44→      return 'Attached parapets on gable roofs snap only to gable-end edges. The eaves are excluded.';
 45→    case 'custom':
 46→      return 'Attached parapets on custom roofs can snap to any roof perimeter edge. Derived drainage still treats eave edges separately.';
