546→        value={u.toDisplay(trussInstance.bearingOffsets?.end || 0)}
547→        onChange={(value) => updateInstance({
548→          bearingOffsets: {
549→            ...(trussInstance.bearingOffsets || {}),
550→            end: u.fromDisplay(value),
551→          },
552→        })}
553→      />
554→      <InputField
555→        label="Overhang A"
556→        type="number"
557→        suffix={u.suffix}
558→        step={u.step(10)}
559→        value={u.toDisplay(trussInstance.overhangs?.start || 0)}
560→        onChange={(value) => updateInstance({
561→          overhangs: {
562→            ...(trussInstance.overhangs || {}),
563→            start: Math.max(0, u.fromDisplay(value)),
564→          },
565→        })}
566→      />
567→      <InputField
568→        label="Overhang B"
569→        type="number"
570→        suffix={u.suffix}
571→        step={u.step(10)}
572→        value={u.toDisplay(trussInstance.overhangs?.end || 0)}
573→        onChange={(value) => updateInstance({
574→          overhangs: {
575→            ...(trussInstance.overhangs || {}),
576→            end: Math.max(0, u.fromDisplay(value)),
577→          },
578→        })}
579→      />
580→      <InputField
581→        label="Roof Link"
582→        value={trussInstance.roofAttachmentId || 'None'}
583→        readOnly
584→      />
585→    </div>
586→  );
587→}
